// // This module implements a 2-bit binary counter with enable and terminal count output. It takes a clock signal (clk), a reset signal (rst), and an enable signal (en). The counter resets to 0 when the reset signal is low. The terminal count output (tc) goes high when the counter reaches its minimum value.
module counter2bit_en_tc (
	input clk,
	input rst,
	input en,
	output reg [1:0] q,
	output tc);

	always @(posedge clk or posedge rst) begin
		if (rst)
			q <= 2'b00;
		else if (en)
			q <= q + 1;
	end

	assign tc = (q == 2'b11) ? 1 : 0;

endmodule
